x","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="demo-hero">\n    <div class="demo-super-d" aria-hidden="true"></div>\n    <div class="demo-hero-inner">\n      <h1>Let\'s Talk About <span>Your Factory</span></h1>\n      <p class="demo-hero-subtitle">Whether you\'re a factory owner seeking solutions or a distributor exploring partnership—we\'ll listen first, then show you what\'s relevant.</p>\n      <div class="demo-trust">\n        <div class="demo-trust-item">\n          <span class="demo-trust-value dw-years">44</span>\n          <span class="demo-trust-label">Years Experience</span>\n        </div>\n        <div class="demo-trust-item">\n          <span class="demo-trust-value">50K+</span>\n          <span class="demo-trust-label">Factories</span>\n        </div>\n        <div class="demo-trust-item">\n          <span class="demo-trust-value">100+</span>\n          <span class="demo-trust-label">Thai Customers</span>\n        </div>\n        <div class="demo-trust-item">\n          <span class="demo-trust-value">300378</span>\n          <span class="demo-trust-label">Stock Listed</span>\n        </div>\n      </div>\n    </div>    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Form"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Form: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Form: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="demo-form-section">\n    <div class="demo-form-inner" style="position:relative;z-index:2;">\n      <div class="demo-form-container">\n        [contact-form-7 id="3ede9be" title="DigiWin Contact Form"]\n        <div class="form-alternative">\n          <p>Prefer to email directly?</p>\n          <a href="mailto:info@digiwin.co.th">info@digiwin.co.th</a>\n        </div>\n      </div>\n\n      <div class="demo-why">\n        <h3>Why Talk to Us?</h3>\n        <div class="why-points">\n          <div class="why-point">\n            <div class="why-icon">\n              <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke-width="2"><circle cx="12" cy="12" r="10"/><path d="M9.09 9a3 3 0 0 1 5.83 1c0 2-3 3-3 3"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>\n            </div>\n            <div class="why-content">\n              <h4>No Sales Pitch</h4>\n              <p>Our first call is about your situation, not our features. We listen before we talk.</p>\n            </div>\n          </div>\n          <div class="why-point">\n            <div class="why-icon">\n              <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke-width="2"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/></svg>\n            </div>\n            <div class="why-content">\n              <h4><span class="dw-years">44</span> Years Manufacturing Only</h4>\n              <p>We understand factories because that\'s all we\'ve ever done. No retail. No hospitality. Just manufacturing.</p>\n            </div>\n          </div>\n          <div class="why-point">\n            <div class="why-icon">\n              <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke-width="2"><path d="M17 21v-2a4 4 0 00-4-4H5a4 4 0 00-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 00-3-3.87m-4-12a4 4 0 010 7.75"/></svg>\n            </div>\n            <div class="why-content">\n              <h4>Local Thai Team</h4>\n              <p>Thai-speaking consultants based in Bangkok. No overseas call centers. Real local support.</p>\n            </div>\n          </div>\n          <div class="why-point">\n            <div class="why-icon">\n              <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke-width="2"><polyline points="20 6 9 17 4 12"/></svg>\n            </div>\n            <div class="why-content">\n              <h4>Thai Revenue Dept. Certified</h4>\n              <p>Already localized for Thai taxation, Withholding Tax, e-Tax integration, and BOI reporting.</p>\n            </div>\n          </div>\n        </div>\n\n        <div class="demo-proof">\n          <span class="demo-proof-label">Why We\'re Different</span>\n          <div class="demo-proof-stats">\n            <div class="proof-stat">\n              <span class="proof-stat-value">72%</span>\n              <span class="proof-stat-label">Taiwan Listed Cos. Trust Us</span>\n            </div>\n            <div class="proof-stat">\n              <span class="proof-stat-value">Foxconn FII</span>\n              <span class="proof-stat-label">Strategic Investor</span>\n            </div>\n            <div class="proof-stat">\n              <span class="proof-stat-value">1,300+</span>\n              <span class="proof-stat-label">R&D Engineers</span>\n            </div>\n            <div class="proof-stat">\n              <span class="proof-stat-value">CMMI 4</span>\n              <span class="proof-stat-label">Certified Since 2010</span>\n            </div>\n          </div>\n        </div>\n      </div>\n    </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Expect"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Expect: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Expect: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="demo-expect">\n    <div class="demo-expect-deco" aria-hidden="true"></div>\n    <div class="demo-expect-inner" style="position:relative;z-index:2;">\n      <div class="demo-expect-header">\n        <h2>What to Expect</h2>\n        <p>No pressure. No obligation. Just a conversation about what\'s possible.</p>\n      </div>\n      <div class="expect-steps">\n        <div class="expect-step">\n          <div class="step-number">1</div>\n          <h3>Discovery Call</h3>\n          <p>We\'ll learn about your factory, challenges, and goals. We ask questions first—no sales pitch. 30-45 minutes.</p>\n        </div>\n        <div class="expect-step">\n          <div class="step-number">2</div>\n          <h3>Tailored Demo</h3>\n          <p>See only the products that fit your needs. We\'ll focus on your industry and specific use cases. No generic slide decks.</p>\n        </div>\n        <div class="expect-step">\n          <div class="step-number">3</div>\n          <h3>Honest Assessment</h3>\n          <p>If there\'s a fit, we\'ll provide a detailed proposal. If not, we\'ll tell you honestly. We\'d rather build trust than force a sale.</p>\n        </div>\n      </div>\n    </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
