INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100569, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n/* Divi injects: @media(max-width:640px){.et_pb_section .et_pb_row{padding:0 24px !important}}\n   Specificity 0,2,0. We use .et_pb_row.et_pb_row (0,2,0 doubled = 0,2,0 still, but\n   .et_pb_section prefix pushes us to 0,3,0) to beat it. */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === HERO (S1) === */\n.demo-hero{background:linear-gradient(135deg,#000432 0%,#000864 50%,#001080 100%);padding:140px 24px 80px;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.demo-hero::before{content:\'\';position:absolute;inset:0;background-image:url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.03\'%3E%3Ccircle cx=\'30\' cy=\'30\' r=\'1.5\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");pointer-events:none}\n.demo-super-d{position:absolute;top:50%;right:auto;left:-15%;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center left;background-size:contain;transform:translateY(-50%);opacity:0.08;pointer-events:none;z-index:0}\n.demo-hero-inner{max-width:800px;margin:0 auto;text-align:center;position:relative;z-index:1}\n.demo-hero h1{font-family:\'Noto Sans\',sans-serif;font-size:clamp(32px,5vw,48px);font-weight:700;color:#fff;margin-bottom:20px;line-height:1.3}\n.demo-hero h1 span{color:#00AFF0}\n.demo-hero-subtitle{font-size:18px;color:rgba(255,255,255,0.85);line-height:1.7;margin-bottom:40px}\n.demo-trust{display:flex;justify-content:center;gap:32px;padding-top:32px;border-top:1px solid rgba(255,255,255,0.1)}\n.demo-trust-item{text-align:center}\n.demo-trust-value{font-family:\'Noto Sans\',sans-serif;font-size:24px;font-weight:700;color:#00AFF0;display:block}\n.demo-trust-label{font-size:12px;color:rgba(255,255,255,0.85)}\n@media(max-width:1024px){.demo-trust{flex-wrap:wrap;gap:24px}}\n@media(max-width:640px){.demo-hero{padding:120px 20px 60px}}\n@media(prefers-reduced-motion:reduce){.demo-super-d,.demo-hero::before{animation:none !important;transition:none !important}}\n/* === FORM (S2) === */\n.demo-form-section{padding:80px 24px;background:#fff;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.demo-form-inner{max-width:1100px;margin:0 auto;display:grid;grid-template-columns:1fr 1fr;gap:64px}\n.demo-form-container{background:#fff;border:1px solid #e2e8f0;border-radius:24px;padding:48px;box-shadow:0 4px 24px rgba(0,0,0,0.06)}\n/* CF7 form header */\n.demo-form-container .demo-form-header{margin-bottom:32px}\n.demo-form-container .demo-form-header h2{font-family:\'Noto Sans\',sans-serif;font-size:28px;font-weight:700;color:#000864;margin-bottom:8px}\n.demo-form-container .demo-form-header p{font-size:15px;color:#5b6b80;margin:0}\n/* CF7 form fields */\n.demo-form-container .form-group{margin-bottom:24px}\n.demo-form-container .form-label{display:block;font-weight:600;color:#000864;margin-bottom:8px;font-size:14px}\n.demo-form-container .wpcf7 input[type="text"],\n.demo-form-container .wpcf7 input[type="email"],\n.demo-form-container .wpcf7 input[type="tel"],\n.demo-form-container .wpcf7 textarea{width:100%;padding:14px 16px;border:1px solid #e2e8f0;border-radius:12px;font-size:16px;font-family:\'Noto Sans\',sans-serif;transition:all 0.2s;box-sizing:border-box}\n.demo-form-container .wpcf7 input:focus,\n.demo-form-container .wpcf7 textarea:focus{outline:none;border-color:#00AFF0;box-shadow:0 0 0 3px rgba(0,175,240,0.1)}\n.demo-form-container .wpcf7 textarea{resize:vertical;min-height:100px}\n/* CF7 checkboxes */\n.demo-form-container .wpcf7-checkbox .wpcf7-list-item{display:block;margin:0 0 8px}\n.demo-form-container .wpcf7-checkbox input[type="checkbox"]{width:18px;height:18px;accent-color:#00AFF0;margin-right:8px}\n/* CF7 acceptance */\n.demo-form-container .wpcf7-acceptance input[type="checkbox"]{width:18px;height:18px;accent-color:#00AFF0;margin-right:8px}\n.demo-form-container .wpcf7-acceptance a{color:#00AFF0;text-decoration:underline}\n/* CF7 submit button */\n.demo-form-container .wpcf7 .form-submit,\n.demo-form-container .wpcf7 input[type="submit"]{width:100%;padding:16px;background:linear-gradient(135deg,#00AFF0,#003CC8);color:#fff;border:none;border-radius:12px;font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;cursor:pointer;transition:all 0.3s}\n.demo-form-container .wpcf7 .form-submit:hover,\n.demo-form-container .wpcf7 input[type="submit"]:hover{transform:translateY(-2px);box-shadow:0 8px 24px rgba(0,175,240,0.3)}\n/* CF7 response messages */\n.demo-form-container .wpcf7-response-output{border-radius:12px;padding:16px;margin:16px 0 0;font-size:14px}\n.demo-form-container .wpcf7-mail-sent-ok{border-color:#02D28C;color:#059669;background:#f0fdf4}\n.demo-form-container .wpcf7-validation-errors{border-color:#dc2626;color:#dc2626;background:#fef2f2}\n.demo-form-container .wpcf7 .wpcf7-not-valid-tip{color:#dc2626;font-size:13px;margin-top:4px}\n.demo-form-container .wpcf7 .wpcf7-spinner{display:none}\n.form-alternative{margin-top:24px;padding-top:24px;border-top:1px solid #e2e8f0;text-align:center}\n.form-alternative p{font-size:14px;color:#5b6b80;margin-bottom:4px}\n.form-alternative a{color:#0369a1;font-weight:600;text-decoration:none}\n.demo-why{padding:0 0 80px}\n.demo-why h3{font-family:\'Noto Sans\',sans-serif;font-size:20px;font-weight:600;color:#000864;margin-bottom:24px}\n.why-points{display:flex;flex-direction:column;gap:20px}\n.why-point{display:flex;gap:16px}\n.why-icon{width:48px;height:48px;background:linear-gradient(135deg,#eff6ff,#dbeafe);border-radius:12px;display:flex;align-items:center;justify-content:center;flex-shrink:0}\n.why-icon svg{width:24px;height:24px;stroke:#00AFF0}\n.why-content h4{font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;color:#000864;margin:0 0 4px}\n.why-content p{font-size:14px;color:#5b6b80;line-height:1.6;margin:0}\n.demo-proof{background:linear-gradient(135deg,#000864,#000432);border-radius:20px;padding:32px;margin-top:40px}\n.demo-proof-label{font-family:\'JetBrains Mono\',monospace;font-size:11px;font-weight:500;color:#15803d;letter-spacing:1px;text-transform:uppercase;display:block;margin-bottom:16px}\n.demo-proof-stats{display:grid;grid-template-columns:repeat(2,1fr);gap:16px}\n.proof-stat{text-align:center;padding:16px;background:rgba(255,255,255,0.05);border-radius:12px}\n.proof-stat-value{font-family:\'Noto Sans\',sans-serif;font-size:24px;font-weight:700;color:#00AFF0;display:block}\n.proof-stat-label{font-size:12px;color:rgba(255,255,255,0.85)}\n@media(max-width:1024px){.demo-form-inner{grid-template-columns:1fr;gap:48px}}\n@media(max-width:640px){.demo-form-container{padding:32px 24px}.demo-proof-stats{grid-template-columns:1fr}}\n@media(prefers-reduced-motion:reduce){.form-input,.form-checkbox-label,.form-submit{animation:none !important;transition:none !important}}\n/* === EXPECT (S3) === */\n.demo-expect{padding:80px 24px;background:linear-gradient(180deg,#F5F7FA 0%,#fff 100%);position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.demo-expect-deco{position:absolute;top:auto;right:-5%;bottom:-5%;left:auto;width:35%;min-height:40vh;background:url("data:image/svg+xml;base64,") no-repeat center right;background-size:contain;opacity:0.06;pointer-events:none;z-index:0}\n.demo-expect-inner{max-width:1000px;margin:0 auto}\n.demo-expect-header{text-align:center;margin-bottom:48px}\n.demo-expect-header h2{font-family:\'Noto Sans\',sans-serif;font-size:36px;font-weight:700;color:#000864;margin-bottom:12px}\n.demo-expect-header p{font-size:17px;color:#5b6b80;margin:0}\n.expect-steps{display:grid;grid-template-columns:repeat(3,1fr);gap:24px}\n.expect-step{background:#fff;border:1px solid #e2e8f0;border-radius:20px;padding:32px;text-align:center;transition:all 0.3s ease}\n.expect-step:hover{box-shadow:0 12px 40px rgba(0,0,0,0.08)}\n.step-number{width:48px;height:48px;background:linear-gradient(135deg,#00AFF0,#003CC8);border-radius:50%;display:flex;align-items:center;justify-content:center;font-family:\'Noto Sans\',sans-serif;font-size:20px;font-weight:700;color:#fff;margin:0 auto 20px}\n.expect-step h3{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#000864;margin-bottom:12px}\n.expect-step p{font-size:14px;color:#5b6b80;line-height:1.6;margin:0}\n@media(max-width:640px){.expect-steps{grid-template-columns:1fr}}\n@media(prefers-reduced-motion:reduce){.expect-step,.demo-expect-deco{animation:none !important;transition:none !important}}\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}');

